(window.courseContent = window.courseContent || {})["000013"] = {"files/Дерматология и венерология/Теми/1-msg-Обривни елементи.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Обривни елементи</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      max-width: 500px;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]s+(.+)/.test(content);\n          let isOl = /^d+.s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]s+(.+)/) : content.match(/^d+.s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/**(.+?)**/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/*(.+?)*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/[(.+?)]((.+?))/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            tooltip.style.left = rect.left + 'px';\n            tooltip.style.top = (rect.bottom + 5) + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center;\"></h1><h1 style=\"text-align: center;\"></h1><p style=\"text-align: center;\"><span style=\"color: rgb(88, 129, 87); font-size: 1.65em; font-weight: 600;\">Обривни елементи</span></p><p>Кожата реагира на разнообразни екзогенни и ендогенни етиологични фактори чрез сравнително малък брой морфологични промени, наречени обривни елементи или кожни ефлоресценции. Те представляват „азбуката на дерматологията“ – чрез техния анализ (локализация, цвят, форма, палпаторна плътност и еволюция) лекарят изгражда правилната диагноза.</p><p>Обривните единици се разделят условно на първични и вторични. Те се класифицират в 6 основни групи, като първите три групи (петнисти, плътни и ексудативни) се считат за предимно първични, а останалите три за вторични:</p><ol><li>Обриви вследствие на промяна на цвета (петнисти).</li><li>Обриви вследствие на промяна на плътността (плътни).</li><li>Обриви, дължащи се на празнина, изпълнена с течност (ексудативни).</li><li>Обриви вследствие на нарушаване целостта на кожата.</li><li>Отпадъчни обривни елементи.</li><li>Обриви, дължащи се на промени в броя и обема на структурните елементи.</li></ol><h2><hr>Петнисти обривни елементи (macula)</h2><p>Макулата е дискретна лезия, разположена на нивото на кожата, която се отличава от околните тъкани единствено по своя цвят. Тя не се палпира и не променя релефа на кожата. Петната се класифицират според механизма на тяхното възникване.</p><h3>Петна вследствие на промяна в кръвообращението</h3><ul><li><strong style=\"white-space-collapse: preserve;\">Macula hyperaemica (Хиперемно петно):</strong><span style=\"white-space-collapse: preserve;\"> Дължи се на временна дилатация на кръвоносните съдове (конгестия). Основен диагностичен белег е изчезването на цвета при витропресия (притискане със стъкло).</span></li></ul><ol><ul><li><p><em>Активна хиперемия:</em> Яркочервени и топли петна.</p></li><li><p><em>Пасивна хиперемия:</em> Синкавочервени и студени на пипане лезии.</p></li><li><p><em>Видове според размера:</em> Розеоли (колкото лещено зърно), еритеми (по-големи и дифузни петна) и еритродермия (обхващаща почти цялата кожна повърхност).</p></li></ul></ol><ul><li><strong style=\"white-space-collapse: preserve;\">Macula anaemica (Анемично петно):</strong><span style=\"white-space-collapse: preserve;\"> Дължи се на локален съдов спазъм или вродена липса на капиляри. Характерно е, че при механично дразнение (фрикция) околната кожа се зачервява, докато петното остава бледо.</span></li><li><p><strong>Macula telangiectatica (Телеангиектатично петно):</strong> Резултат от трайно и необратимо разширение на капилярите. Има яркочервен до виолетов цвят и само частично избледнява при натиск.</p> Може да бъде вродено (naevus araneus) или придобито (rosacea).</li><li><strong style=\"white-space-collapse: preserve;\">Macula haemorrhagica (Хеморагично петно):</strong><span style=\"white-space-collapse: preserve;\"> Възниква при излизане на кръв извън съдовото легло в кожата или лигавиците. </span><b style=\"white-space-collapse: preserve;\">Важно</b><span style=\"white-space-collapse: preserve;\">:</span><span style=\"white-space-collapse: preserve;\"> тези петна не изчезват при витропресия. Цветът им преминава през еволюция (червен, виолетов, зелен, жълт) поради разграждането на хемоглобина.</span></li></ul><ol><ul><li><p><em>Класификация по форма и размер:</em> Петехии (точковидни), ехимози (колкото монета), вибицес (ивицести), суфузии/сугилации (обширни кръвоизливи) и хематоми (масивни колекции, оформящи подутина). Общият термин за тези състояния е пурпура.</p></li></ul></ol><h3>Петна вследствие на промяна на пигментацията</h3><ul><li><strong>Macula hyperchromica:</strong> Възниква при натрупване на меланин, каротин, хемосидерин или чужди пигменти (татуировка). Биват вродени (лунички, лентиго) или придобити (мелазма).</li><li><strong>Macula achromica (hypochromica):</strong> Ахромичното петно се дължи на липса или намалено количество меланин в епидермиса. Вродени форми са албинизмът и naevus depigmentosus, а придобити — витилигото.</li></ul><ul><li><strong>Macula dyschromica:</strong> Съчетание на хиперпигментни с ахромични участъци.</li></ul><h2><hr>Плътни обривни елементи</h2><p>Тези елементи се характеризират с промяна в плътността на кожата и се установяват чрез оглед и палпация. Те проминират над кожното ниво или се усещат като инфилтрати в дълбочина.</p><h3>Видове плътни елементи</h3><ul><li><strong>Papula (възелче):</strong>&nbsp;<p>Ограничено плътно образувание, което преминава без образуване на белег.</p></li><ul><li><p><em>Размери:</em> Милиарни (просено зърно), лентикуларни (лещено зърно) и нумуларни (колкото монета). </p></li><li><p><em>Форми:</em> Конични, полигонални, полусферични. При сливане на няколко папули се образува плака.</p><br></li><li><p><i>Хистопатологично</i> се делят на епидермални, дермо-епидермални и дермални.</p></li></ul><li><strong>Nodus (възел):</strong> Плътна, закръглена или елипсовидна лезия, която се палпира в дълбочина в дермата и хиподермата. По-малките се наричат нодули (nodulus). Големите възли в хиподермата могат да се слеят (например erythema nodosum).</li><li><strong>Tumor (тумор):</strong> В широк смисъл това е всяко закръглено плътно образувание, независимо от произхода му (възпаление, киста, неоплазма). В тесен смисъл се отнася до неоплазиите.</li><li><strong>Urtica (кабар):</strong> Ограничен, надигнат или плосък, бързопреходен елемент, променящ формата и размерите си. Придружен е от силен сърбеж. Дължи се на ограничен оток в дермата. Възниква при контакт с коприва, ухапване от насекоми или уртикария.</li><li><strong>Vegetatio (вегетация):</strong> Ограничено на малка основа, надигнато туморовидно образувание с неравна повърхност&nbsp;<p>(наподобяваща цветно зеле)</p>. Дължи се на патологично разрастване на епидермиса и дермалните папили (например verruca vulgaris, condylomata acuminata).</li><li><strong>Lichenificatio (лихенификация):</strong> Хронично задебеляване на епидермиса със засилване на кожния релеф и хиперпигментация. Характерна е за ендогенна екзема (невродермит).&nbsp;<p>Може да се развие и вторично в резултат на хроничен възпалителен процес на кожата.</p></li><li><strong>Hyperkeratosis (хиперкератоза):</strong> Задебеляване на роговия слой на кожата (ограничено или дифузно). При фоликуларна хиперкератоза повърхността прилича на пила. Дифузна хиперкератоза на дланите и стъпалата е характерна за някои генодерматози.</li></ul><h2><hr>Ексудативни обривни елементи</h2><p>Тези лезии се дефинират от наличието на кухина, изпълнена с течност (ексудат), възникнала вследствие на възпалителен процес.</p><h3>Видове ексудативни елементи</h3><ul><li><strong>Vesicula (мехурче):</strong> Малко кухилно образувание, изпълнено със серозен, хеморагичен или друг ексудат. Могат да бъдат субкорнеални, интраепидермални или субепидермални. Биват еднокамерни или многокамерни. При разкъсване се образуват ерозии, а при засъхване — крусти. Везикулозният обрив е характерен за екземата, херпесите и други булозни дерматози.</li><li><strong>Bulla (була, мехур):</strong> Ексудативен елемент с диаметър над 0,5 см. Разликата от везикулата е само в големината. Хлабавият плосък мехур се нарича фликтена (phlyctaena).</li><li><strong>Pustula (гнойно мехурче):</strong> Ограничена лезия с жълтеникав цвет, съдържаща гной. Разполага се често в изходните отвърстия на космените фоликули, в потните жлези или в интерфоликуларния епидермис. Вторичното инфектиране на везикулозни лезии се нарича импетигинизация. Пустула с некротична основа се нарича ектима (ecthyma).</li><li><strong>Abscessus (гнойник):</strong> Ограничено остро възпаление на дълбоките слоеве на кожата, характеризиращо се с колекция от гной в образувана кухина чрез дезинтеграция или некроза на тъканите. Започва като тестоват възел, който се размеква (флуктуира) и накрая се отваря, при което изтича гноевидна материя.</li><li><strong>Cysta (киста):</strong> Затворена кухина или сак, постлан с епител и съдържащ течност или полутечна материя. Разполага се в дермата, хиподермата или в лигавиците. Биват вродени и придобити (например dermoidalis).</li></ul><hr><h2>Обривни елементи вследствие на нарушаване на целостта на кожата</h2><p>Тези елементи възникват в резултат на различни патологични процеси (възпалителни, съдови, некротични), при които увредените тъкани се елиминират, оставяйки дефект върху повърхността на кожата.</p><ul><li><strong>Erosio (олузване):</strong> Представлява повърхностно нарушение на целостта, което засяга само епидермиса или епитела на лигавиците като оздравява без цикатрикс. Най-често се появява след разкъсване на свода на везикули или були, както и след мацерация на епидермиса. Тъй като дермата остава незасегната, ерозията оздравява напълно без остатъчен белег. Дъното на ерозията обикновено е обилно мокро. Характерни са за заболявания като пемфигус, остра екзема и булозна епидермолиза.</li><li><strong>Excoriatio (одраскване):</strong> Това е механично нарушаване на целостта на кожата, което обикновено има линеен характер. То е резултат от интензивно разчесване при силно сърбящи дерматози като невродермит, скабиес или акне. Ако засягането е само повърхностно, то оздравява без белег, но по-дълбоките екскориации, ангажиращи дермата, оставят цикатрикси.</li><ul><li>Специфичен обривен елемент е скабуозният ход (ductulus femelae), който се наблюдава при крастата. Той представлява зигзагообразен линеен канал, който женският акар пробива в роговия слой на епидермиа, за да снесе своите яйца. У нечистоплътните индивиди той има тъмносив цвят и изглежда като драскотина, на която в единия край има везикула.</li></ul><li><strong>Fissura, rhagada (цепнатина):</strong> Линеен дефект на кожата или полулигавиците с различна дълбочина. Често се наблюдава при естествените отвори на тялото (уста, нос, анус), където има разтягане на кожата или полулигавицата. Обикновено се предшества от възпалителен процес и е силно болезнена. Плитките цепнатини засягат само епидермиса (фисури), докато по-дълбоките достигат до дермата (рагади).</li><li><strong>Fistula (фистула):</strong> Абнормен канал, който свързва кухина в дълбоките слоеве на кожата с повърхността или свързва две дълбоко разположени кухини помежду им. Те могат да бъдат вродени или придобити. Придобитите фистули възникват при разпадане на тъкани в резултат на хронични патологични процеси (коликвативна туберкулоза, актиномикоза и други.)</li><li><strong>Ulcus (язва):</strong> Дълбоко и трайно нарушение на целостта на кожата, което засяга дермата, хиподермата, а понякога и подлежащите тъкани (мускули, кости). Възниква в резултат на отпадане на некротични маси при възпалителни, съдови (варикозни) или неопластични процеси. Язвата винаги оздравява с цикатрикс. Клиничното изследване трябва да обърне внимание на локализацията, формата, големината, дъното (гладко, гранулиращо, с налеп или некроза) и състоянието на ръбовете (подрити, издигнати, фестонирани). Язвата се отличава от раната (vulnus), която е резултат от механична травма и не е предшествана от патологичен процес. Язвата е характерна за туберкулозата, третичния сифилис, лепрата, дълбоките микози, васкулитите, постромбофлебитния синдром и при различни кожни неоплазми.</li><li><strong>Aphtha (афта):</strong> Специфичен елемент по лигавиците, представляващ овална ерозия, покрита с белезникав (фибринозен) налеп и обкръжена от яркочервена ареола.</li></ul><hr><h2>Отпадъчни обривни елементи</h2><p>Тези елементи се развиват в хода на еволюцията на предхождащи ги плътни или ексудативни ефлоресценции.</p><ul><li><strong>Squama (люспа):</strong> Представлява излющени повърхностни рогови клетки, които се отделят под формата на плоски люспи. Появата им е резултат от нарушена или ускорена кератинизация (хипер- или паракератоза). Според големината се делят на трицевидни (desquamatio pityroides) и листовивдни (desquamatio lamellosa). Цветът може да бъде сребристобял (при псориазис), жълтеникав или тъмен до черен (при ихтиоза и acanthosis nigricans).</li><li><strong>Crusta (кора):</strong> Образува се при засъхване на повърхността на кожата на серозен ексудат, гной или кръв. Цветът варира според съдържанието: светложълтеникав (серозен ексудат), жълто-зелен (гной) или кафяво-черен (кръв). Крустите често покриват ерозии, улкуси, фистули и рагади. Специфична форма е рупията (стълповидно наслоена круста) и скутулумът (при фавус).</li><li><strong>Eschara (есхара):</strong> Суха некроза на кожата с тъмен до черен цвят. Тя е резултат от тежки циркулаторни смущения (исхемия) или външно каустично (химично) въздействие. След отпадането на есхарата винаги остава язва и впоследствие белег.</li><li><b>Comedon (комедон):</b>&nbsp;<p style=\"\">Отворен комедон (черна точка) представлява запушалка от рогови клетки, себум и меланин в отвърстието на мастно-космения фоликул и е характерен за акнето. </p><p>Затвореният комедон е белезникаво възелче, предшественик на папула.</p></li><li><b>Indumentum (налеп)</b>: Белезниква налеп, състоящ се от дексвамиран епител, фибриноидна материя, микроорганизми и др. Той е характерен обривен елемент по лигавицата на устата.</li></ul><h2><hr>Обриви, дължащи се на промени в броя и обема на структурните елементи на кожата.</h2><ul><li><strong>Atrophia (атрофия):</strong> Представлява редуциране на някои или на всички слоеве на кожата. Атрофичната кожа е изтъняла, с изгладен релеф и редуцирани кожни придатъци (косми, мастни жлези). Тя може да бъде:</li><ul><li><i>Ограничена атрофия</i>: на епидермиса (при lichen sclerosus), на еластичните влакна в дермата (при anetodermia), на хиподермата (при липоатрофия) и т.н.</li><li><i>Дифузна атрофия</i>: при остаряване, излагане на лъчеви въздействия и др.</li><li><b>Пойиколдермия</b>: Съчетанието на атрофия, телеангиектазии и пигментни нарушения. Най-често тя възниква при лъчеви въздействия върху кожата (с X-лъчи, УВЛ и др.)</li></ul><li><strong>Hypertrophia (хипертрофия):</strong> Увеличаване на обема на структурните елементи на кожата, което често е съчетано с хиперплазия. Кожата изглежда задебелена, груба и втвърдена. Възниква при хронично възпаление на кожата (напр. при елафантиаза).Пример за това е слонската болест (елефантиаза) при хронично възпаление.</li><ul><li><b>Дерматосклерозата </b>е уплътняване на кожата, което се дължи на фиброза и склероза.</li></ul><li><strong>Cicatrix (белег, ръбец):</strong> Новообразувана съединителна тъкан, която замества нормалните структури на кожата, разрушени от предходно заболяване или травма. Биват:</li><ul><li><em>Атрофични:</em> под нивото на кожата, изтънени.</li><li><em>Хипертрофични (келоиди):</em> надигнати над нивото, плътни и често болезнени.</li><li><em>Интерстициални:</em> развиват се без видимо нарушение на целостта на кожата (при разнасяне на инфилтрати).</li></ul></ul><hr><h2>Обривни елементи по лигавицата на устата (enanthema)</h2><p>Обривите по лигавиците (енантеми) показват голямо сходство с кожните ефлоресценции (екзантеми), но поради специфичните анатомични особености на лигавицата — липсата на рогов слой и постоянната влажна среда — те са по-малко на брой и по-еднообразни по вид. Клиничната картина на енантемите се характеризира със следните групи елементи:</p><h4>1. Петнисти обривни елементи по лигавицата на устата</h4><ul><li><strong>Хиперемични петна (Еритеми):</strong> Поради естествения червен цвят на лигавицата, еритемите често са по-слабо забележими, отколкото по кожата. </li><ul><li><em>Розеоли:</em> Малки петна с големина колкото лещено зърно, които често са характерни за лекарствени увреждания. </li><li><em>Дифузни еритеми:</em> Големи и разлети зачервявания, които се наблюдават при остри инфекциозни заболявания като сифилис, морбили и скарлатина. Те могат да възникнат и локално при механично дразнене, например от зле прилягащи зъбни протези.</li></ul><li><strong>Хеморагични петна:</strong> Те са по-дифузни по лигавицата, но личат много по-ясно. Срещат се при състояния като хеморагични диатези, лептоспироза и други системни инфекции.</li><li><strong>Хиперхромни петна:</strong> Дължат се на отлагане на пигменти. Те могат да бъдат резултат от натрупване на меланин (наблюдава се при расово обусловена пигментация или при ендокринни заболявания като Адисонова болест) или от натрупване на тежки метали (олово, бисмут, живак) при хронични интоксикации.</li></ul><h4>2. Плътни обривни елементи по лигавицата на устата</h4><p>Възникват вследствие на възпалителни или неопластични процеси в лигавицата и проминират над повърхността или се палпират в дълбочина. Поради серозното имбибиране те изглеждат белезникави и често стават ерозивни.</p><ul><li><strong>Папули (Възелчета):</strong> Те често се сливат и образуват плаки, което е типичен белег за заболявания като вторичен сифилис и лихен планус (lichen planus).</li><li><strong>Възли:</strong> Наблюдават се при грануломатозни специфични процеси. В хода на своята еволюция те могат да се склерозират или да некротизират, водейки до образуването на язви, които впоследствие оздравяват с цикатрикси.</li><li><strong>Вегетации (Vegetatio):</strong> Представляват патологично разрастване на папиларния слой на tunica propria и покриващия го епител. Когато са на широка основа или на краче, те се дефинират като папиломатоза (papillomatosis).</li><li><strong>Левкоплакия:</strong> Това е своеобразна метаплазия на невроговяващия епител на лигавицата. Характеризира се със задебеляване и засилване на паракератотичното вроговяване (hyperkeratosis), което клинично се проявява под формата на плътни белезникави плаки.</li></ul><h4>3. Ексудативни обривни елементи по лигавицата на устата</h4><p>Тези елементи се дефинират от наличието на кухина с течност, но имат много кратка еволюция поради нежността на лигавичния епител. Бързо преминават в ерозивни лезии.</p><ul><li><p><em>Везикулозните обриви</em> са характерни за заболявания от херпесната група.</p></li><li><p><em>Булозните обриви</em> се наблюдават при пемфигус, еритема мултиформе и други.</p></li></ul><div><h4>4. Обриви вследствие на нарушаване целостта на лигавицата</h4><p>Най-специфичният елемент в тази група за устната кухина е афтата.</p><ul><li><strong>Афта (Aphtha):</strong> Представлява специфичен дефект на лигавицата — овална ерозия, покрита със сиво-белезникав серофибринозен налеп. Тя е обкръжена от яркочервена възпалителна ареола. Афтите са изключително болезнени, особено при механично дразнене (хранене, говор).</li></ul><h4>5. Отпадъчни елементи и специфични промени</h4><p>След преминаване на основните обривни елементи или при специфични хронични състояния се наблюдават:</p><ul><li><strong>Налеп (Indumentum):</strong> Състои се от десквамиран (излющен) епител, фибринозна материя, микроорганизми и захаромицети и има различен цвят, най-често белезникав. Наблюдава се основно по букалната лигавица и езика при инфекциозни и фебрилни състояния.</li><li><strong>Люспи (сквами) и Крусти:</strong> Тези елементи не са типични за вътрешната част на устната кухина, а се наблюдават предимно по устните (полулигавицата) при състояния като ексфолиативен хейлит или еритема мултиформе.</li><li><strong>Цикатрикси (Белези):</strong> Лъскавата и влажна повърхност и яркоеритемният цвят на лигавицата невинаги позволяват да се видят малките цикатрикси и атрофии. Релефът на лигавицата в областта на цикатрикса е заличен поради липсата на слузести жлези. В зависимост от своята локализация и тежест, цикатриксите могат да доведат до сериозни функционални нарушения като затруднено гълтане или говор.</li></ul></div><br><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false}\n  ]\n});\n</script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false}\n  ]\n});\n</script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false}\n  ]\n});\n</script>\n</body>\n</html>","files/Дерматология и венерология/Теми/2-msg-Методи на изследване в дерматологията - клинични, лабораторни.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Методи на изследване в дерматологията - клинични, лабораторни</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\">Клинични методи за изследване в дерматологията</h1><p>Поради достъпността на патологичните процеси по кожата и лигавиците, изследванията могат да се провеждат в различни етапи от тяхната еволюция.</p><h2>1. Inspectio (Оглед)</h2><p>Огледът е най-широко използваният метод за изследване в дерматологията.</p><ul><li><strong>Условия:</strong> Трябва да се извършва на достатъчна разсеяна дневна светлина, идваща откъм гърба на лекаря и падаща директно върху кожата.</li><li><strong>Обхват:</strong> Необходимо е да се огледа цялата кожа, включително лигавици, гениталии и перианална област, дори ако пациентът ги смята за незасегнати.</li><li><strong>Системен подход:</strong> Огледът започва от окосмената част на главата и преминава последователно през лицето, устата, лигавиците, шията, туловището, аксиларните ямки, гърба, корема, гениталиите, перианалната област, крайниците, дланите и ходилата, като завършва с<p> кожните придатъци </p><p>(косми и нокти)</p></li><li><strong></strong><p>Преценяват се индивидуалните особености на незасегнатата от обрива кожа и видими лигавици:</p> цвят (бледа, еритемна, пигментирана), релеф, влажност, омазняване и <p>състояние на окосмяването, състояние на ноктите (цвят, повърхност и т.н.)</p></li><li><strong>Морфология на обрива:</strong></li><ul><li><p>Специално внимание се обръща на локализацията и характера (морфологията и</p><p>начина на подреждане) на обривните </p><p>елементи. </p><br></li><li><p>Обривът може да се състои от </p><p>единични или множествени лезии, които да </p><p>са разположени в ограничен участък </p><p>(циркумскриптно), в определен дерматом </p><p>(сегментно, зостериформено) или област </p><p>(регионално), в едната половина на тялото </p><p>(унилатерално) или да са генерализирани </p><p>(универсално).</p><br></li><li><p>Елементите могат да бъдат пръснати по цялата кожа (дисеминирани), групирани (агминирани) или слети (конфлуиращи).</p><br></li><li><p>Обривът </p><p>бива мономорфен (състои се от един вид елементи) или полиморфен (различни видове). </p><p>Полиморфизмът може да бъде </p><p>еволютивен.</p></li><li><p>Обръща се внимание и на симетричността и асиметричността на разположението на лезиите.</p><br></li><li><p>Обривните елементи могат да са подредени — линеарно, </p><p>ануларно (пръстеновидно), гиратно </p><p>(гирляндовидно), полициклично, херпетиформено, ретикуларно и др. </p></li><li><p>Границите </p><p>на лезиите могат да бъдат рязко отграничени или неясни.</p></li></ul></ul><hr><h2>2. Palpatio (Палпация)</h2><p>Палпацията се извършва с палмарната повърхност на пръстите чрез притискане на кожата в дълбочина.</p><ul><li>При наличие на ексудация,&nbsp;<p>нарушение на целостта на кожата </p><p>(напр. сифилис — ulcus durum) и импетигинизация</p> се препоръчва използването на ръкавица.</li><li>Чрез палпация се определят плътността, големината, релефа, дълбочината на процеса (ангажиране на подлежащи тъкани), температурата, влажността, тургора, наличието на болезненост или флуктация (при гнойна колекция).</li><li>Палпаторно се търсят и системно увеличени лимфни възли.</li></ul><hr><h2>3. Специфични клинични тестове</h2><h3>Дермографизъм</h3><p>Това е съдова реакция, която се провокира върху кожата на тялото (обикновено на гърба) чрез умерен натиск и плъзгане с нокът или твърд предмет.</p><ul><li><strong>Нормална реакция:</strong> Първоначално се появява бяла ивица (бял дермографизъм), която след 5–15 секунди става розово-червена (червен дермографизъм) и трае до 1 минута.</li></ul><h3>Frictio (Фрикция)</h3><p>Метод за определяне на съдовата реакция чрез триене.</p><ul><li><strong>Симптом на Darier:</strong> Поява на уртикоподобен обрив след енергично триене на пигментни лезии при мастоцитоза.</li><li><strong>Симптом на Никольский:</strong> Свличане на епидермиса при енергичен натиск и плъзгане близо до булозни лезии, доказващо акантолиза при пемфигус.</li></ul><h3>Системно остъргване (Кюртаж)</h3><p>Извършва се с нокът или кюретка за постепенно сваляне на натрупаните сквами. По този начин се установява <strong>знакът на Auspitz</strong> при псориазис.</p><h3>Маркиране на кожата</h3><p>Намазването на кожата с масла или бои допринася за по-ясното открояване на определени изменения:</p><ul><li><strong>Pityriasis versicolor:</strong> Приложението на йодна тинктура прави ефлоресценциите по-видими</li><li><strong>Скабиес (Краста):</strong> С мастило се маркират и визуализират скабиесните ходове</li><li><strong>Lichen ruber planus:</strong> Използването на растително масло помага за изпъкването на стриите на Wickham.</li></ul><h4>Изследване на кожната сетивност</h4><ul><li><strong>Тактилна сетивност (допир):</strong> Определя се чрез докосване на симетрични кожни участъци с памук, мека четка или главичка на топлийка.</li><li><strong>Термосетивност (топло и студено):</strong> Използват се епруветки, пълни съответно с топла и студена вода.</li></ul><h4>Витропресия (Диаскопия)</h4><p>Методът включва притискане на патологичния участък с предметно стъкло или стъклена шпатула за определяне на неговия цвят:</p><ul><li><strong>Tuberculosis cutis luposa:</strong> При диаскопия лупомите изглеждат жълто-кафяви, наподобявайки „ябълково желе“.</li><li><strong>Диференциална диагностика:</strong> За разлика от хиперемичните макули, хеморагичните макули не променят цвета си при витропресия.</li></ul><h4>Оглед с лупа</h4><p>Използва се увеличение от 4 до 10 пъти за установяване на фини детайли в обривните елементи:</p><ul><li>Стрии на Wickham при <strong>lichen ruber</strong>.</li><li>Фоликуларна хиперкератоза при <strong>хроничен еритематозус</strong>.</li><li>Скабиозните ходове и разширените отвори на мастните жлези при <strong>себорея</strong></li></ul><h4>Дерматоскопия (Епилуминесцентна светлинна микроскопия)</h4><p>Извършва се със специален дерматоскоп или светлинен микроскоп.</p><ul><li><strong>Същност:</strong> Неинвазивен клиничен метод, който използва оптичния феномен на маслената имерсия за изследване <em>in vivo</em> на промените в епидермиса и дермата.</li><li><strong>Приложение:</strong> Изключително полезна за ранна диагностика на малигнен меланом и за диференциална диагностика на различни пигментни лезии по кожата.</li></ul><h1 style=\"text-align: center\"><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\">Лабораторни методи за изследване</h1><p>В дерматологичната практика лабораторните и инструменталните методи играят ключова роля, допълвайки клиничната диагностика.</p><h2>1. Общи параклинични изследвания</h2><p>Рутинните изследвания на кръв и урина са задължителни за оценка на функционалното състояние на органите:</p><ul><li><strong>Еозинофилия:</strong> Насочва към някои алергодерматози.</li><li><strong>СУЕ:</strong> Ускорена при <em>erysipelas</em>, <em>erythema nodosum</em> и др.</li><li><strong>Кръвна захар:</strong> Повишените нива често се свързват с пиодермии и микози.</li><li><strong>Специализирани изследвания:</strong> При нужда се извършват разширени хематологични (напр. левкози) или биохимични анализи (електролити, ензими, белтъчни фракции).</li></ul><hr><h2>2. Морфологични изследвания</h2><h3>Цитологични методи (Проба на Tzanck)</h3><p>Бърз метод за диагностика на булозни дерматози, дерматовирози и неоплазии.</p><ul><li><strong>Техника:</strong> Материал от дъното на мехур се нанася върху стъкло, фиксира се и се оцветява по Giemsa.</li><li><strong>Диагностични маркери:</strong></li><ul><li><strong>Акантолитични клетки:</strong> Доказват пемфигус.</li><li><strong>Еозинофили, полиморфонуклеари и лимфоцити:</strong> Насочват към болест на Duhring.</li><li><strong>Ядрени/цитоплазмени включвания:</strong> Характерни за различните дерматовирози.</li></ul></ul><h3>Хистопатологично изследване (Биопсия)</h3><p>Най-доказателственият метод при хронични и неопластични кожни заболявания.</p><ul><li><strong>Техника:</strong> Пробна ексцизия под локална анестезия. Хистологичните срези обикновено се оцветяват с хематоксилин-еозин.</li><li><strong>Допълнителни методи:</strong> Използват се хистохимични оцветявания и белязани с мононуклеарни антитела методи.</li></ul><h3>Електронномикроскопски изследвания</h3><p>Навлизат в рутинната практика, особено важни за пренаталната и постнаталната диагностика на генодерматози.</p><hr><h2></h2><h2>3. Алергологични тестове</h2><p>Алергологичните тестове се делят на две основни групи:</p><ul><li><strong>Директни:</strong> Извършват се директно върху пациента (крият опасност за него).</li><li><strong>Индиректни:</strong> Извършват се извън тялото (in vitro), чрез серум или кръвни елементи на болния.</li></ul><h3>Процедури за доказване на етиологична връзка</h3><p>Прости и достъпни способи за доказване на връзката между алергена и клиничния синдром:</p><ul><li><strong>Елиминационни тестове:</strong> Завяхването на обривите след елиминиране на алергена доказва неговата роля.</li><li><strong>Експозиционни тестове:</strong> Засилването на обривите след прием на храна, лекарства или кожен контакт с алергена подкрепя неговата етиологична роля.</li><li><strong>Провокационни тестове:</strong> Подкрепят се чрез хематологични показатели. Тестът е положителен, ако след прием на алергена левкоцитите намалеят под 1 G/l или тромбоцитите намалеят с 50 G/l.</li></ul><h3>Кожно-алергични проби</h3><p>Основават се на принципа, че алергенът се свързва с IgE антитела (върху мастоцити) или със сензибилизирани лимфоцити. Силата на местната алергична реакция зависи от нивото на специфичните антитела и сензибилизираните лимфоцити в кожата и от концентрацията на алергена.</p><h4>Епикутанни проби (Метод на Jadassohn-Bloch / Patch test)</h4><ul><li><strong>Провеждане:</strong> Т<p>естуваното вещество се подготвя в алергична концентрация и се поставя в подходящ носител (вода, вазелин и др.). Нанася се върху марля или филтърна хартия (с размер 1 cm²), поставя се върху почистена, интактна кожа (обикновено на гърба) и се фиксира с хипоалергичен лейкопласт.</p></li><li><strong>Отчитане:</strong> На 48-ия и 72-ия час по четирибалова скала:</li><ul><li>(+) – еритем</li><li>(++) – еритем и едем</li><li>(+++) – еритем, едем и везикулация</li><li>(++++) – некроза</li></ul><li><strong>Забележка:</strong> Негативният тест не изключва сензибилизация. Чувствителност/специфичност: 60–80%.</li></ul><h4>Скарификационни проби</h4><ul><li><strong>Провеждане:</strong> <p>Извършва се върху воларната (вътрешната) повърхност на предмишницата. Кожата се подготвя чрез одраскване (scratch) или убождане (prick) със стерилна игла или специално стило. Нанесеният алерген (разтвор или суспензия) прониква в ерозираната зона. Пробите се поставят на разстояние 3 cm една от друга.</p></li><li><strong>Отчитане:</strong> На 20-ата минута и 24-ия час според размера на еритема:</li><ul><li>(+) – 3–5 mm</li><li>(++) – до 7 mm</li><li>(+++) – до 10 mm</li><li>(++++) – над 10 mm</li></ul><li><strong>Приложение:</strong> Най-често за тестуване на антибиотици. Контролата с дестилирана вода трябва да е негативна.</li></ul><h4>Интрадермални проби</h4><ul><li><strong>Провеждане:</strong> <p>Използва се туберкулинова спринцовка, с която се инжектират 0,02 cm³ от стандартен алерген в дермата. Извършва се на воларните повърхности на предмишниците, на разстояние 3 cm</p>.</li><li><strong>Стандартна серия:</strong> Включва хранителни алергени (свинско месо, риба, белтък, жълтък), полени (домашен прах, тревен полен) и бактериални/фунгиални алергени (α-хемолитичен стрептокок, Staph. aureus, групов фунгиален и кандидин).</li><li><strong>Отчитане:</strong> На 20-ата минута и 24-ия час <p>се измерва общият размер на папулата и еритема</p>:</li><ul><li>(-) – папула и еритем до 7 mm</li><li>(+) – до 10 mm</li><li>(++) – до 12 mm</li><li>(+++) – до 15 mm</li><li>(++++) – над 15 mm</li></ul></ul><div><h3>Индиректни методи</h3></div><ul><li><strong>Реакция на Prausnitz-Kustner:</strong> Серум от алергично болен се инжектира в кожата на здрав дробоволец. След 24 часа на същото място се инжектира предполагаемият алерген; <p>При наличие на антитела в серума на болния спрямо този алерген настъпва реакция</p><p>в кожата на реципиента.</p></li></ul><ul><li><strong>Други in vitro методи:</strong> Лимфотрансформационен тест, радиоалергосорбентен тест (RAST) и др., с които се диагностицират алергодерматозите.</li></ul><div><hr><h2>4. Микологични изследвания</h2><p>Доказването на микотична инфекция се основава на пет основни подхода за идентификация на причинителя:</p><ul><li><strong>Диагностика със светлина на Wood:</strong></li><ul><li><strong>Метод:</strong> Използва се специална лампа с „черна светлина“ (емисия 365 nm). Тя предизвиква специфична флуоресценция на поразените участъци.</li><li><strong>Клинични белези:</strong> При микроспория флуоресценцията е <strong>яркозелена</strong>; при <em>pityriasis versicolor</em> — <strong>златистожълта</strong>; при еритразма — <strong>розова</strong>.</li><li><strong>Друго приложение:</strong> Използва се при пигментни нарушения, порфирии и диагностика на лекарствени дерматози.</li></ul><li><strong>Микроскопско изследване на нативен препарат:</strong></li><ul><li><strong>Техника:</strong> Патологичният материал (остъргани сквами, косми, нокти) се поставя на предметно стъкло. Добавя се 30% калиева основа и се загрява леко, за да се размекне кератинът и препаратът да стане прозрачен.</li><li><strong>Наблюдение:</strong> Наблюдава се на светлинен микроскоп. Дерматофитите се разпознават като двойно контурирани септирани нишки (хифи) или окръглени спори, а <em>Candida</em> — като несептирани нишки.</li></ul><li><strong>Културелно изследване:</strong></li><ul><li><strong>Метод:</strong> Материалът се посява върху твърда хранителна среда на Sabouraud и се инкубира.</li><li><strong>Инкубация:</strong> <em>Candida</em> пониква за 3–7 дни при 37°C, а дерматофитите за 15–20 дни при 28°C.</li><li><strong>Идентификация:</strong> Определя се чрез морфология на колониите: повърхност, периферни ръбове и пигментация. Възможно е наблюдение през стената на епруветката за морфологични детайли.</li></ul><li><strong>Хистологично идентифициране:</strong></li><ul><li>Използват се специфични оцветявания на тъканни срези: ПАС реакция за дерматофити, Gram за актиномицети/нокардии и импрегнация по Gomori за дълбоки микози.</li></ul><li><strong>Серологично доказване:</strong> Чрез откриване на специфични антитела срещу микотичния агент в кръвния серум.</li></ul><hr><h2></h2><h2>5. Микробиологични изследвания</h2><p>При инфекциозни дерматози (пиодермии, туберкулоза, лепра и др.) и полово предавани болести задължително се провежда микробиологично изследване на патологичния материал, включващо микроскопски, културелни и серологични методи.</p><h3>5.1. Микроскопски изследвания</h3><p>При венерично болни се извършват следните видове наблюдения:</p><ul><li><strong>Нативен препарат:</strong> За откриване на трихомони в уретрален ексудат.</li><li><strong>„Тъмно поле“ (ултрамикроскопия):</strong> За доказване наличието на трепонеми при ерозивни лезии. </li><li><strong>Оцветени препарати:</strong></li><ul><li><strong>По Gram (при жени) или с метиленово синьо (при мъже):</strong> За гонококи в ексудат от уретра, цервикален канал, ректум, конюнктива или фаринкс.</li><li><strong>По Giemsa:</strong> За диагностика на хламидии.</li><li><strong>Флуоресцентно свързани антитела:</strong> За специфично доказване на трепонеми, хламидии и др.</li></ul></ul><h3>5.2. Културелни изследвания и антибиограма</h3><p>Културелното изследване на патологичен материал дава информация за вида на бактериалния причинител. Чрез <strong>антибиограма</strong> се определя неговата резистентност към различните антибиотици, което насочва избора на подходяща терапия.</p><h3>5.3. Молекулярно-биологична диагностика (PCR)</h3><p><strong>Полимеразната верижна реакция (PCR)</strong> е метод, чрез който се открива и амплифицира търсената специфична ДНК секвенция на определен бактерий, вирус или микотичен агент, с което категорично се доказва наличието му в изследвания материал.</p><h3>5.4. Серологична диагностика</h3><p>Серологичната диагностика се основава на доказване наличието на антитела (имуноглобулини М, G, А, Е) в кръвния серум на болните срещу съответните причинители. Прилага се при борелиоза, сифилис, хламидийни инфекции, СПИН и др. Тестовете се делят на:</p><ul><li><strong>Скриниращи (пресяващи):</strong> За първоначално отсяване.</li><li><strong>Потвърдителни:</strong> Базиращи се на доказване на специфични антитела.</li></ul><p><strong>Пример: <span class=\"editor-note\" data-note=\"**Класически (липоидни) тестове:** Включват реакцията за свързване на комплемента (Wasserman) и флокулационни тестове.\n**Специфични (трепонемни) тестове:**\n- Реакция за имобилизация на бледата трепонема (TPI, Nelson-Mayer);\n- Хемоаглутинационна проба (ТРИА);\n- Имунофлуоресцентна проба (FTA-Abs);\n- Имуноензимна проба (ELISA).\" id=\"note-1772969624959-0\">Диагностика на сифилис.</span></strong></p><div><hr><h2>6. Имунофлуоресцентни изследвания</h2><p>Имунофлуоресцентните методи са ключови в дерматологията за доказване на антитела (IgA, IgG, IgM), компоненти на комплемента и други патогенни антигени в структурата на кожата и лигавиците.</p><h3>6.1. Видове имунофлуоресценция</h3><ul><li><strong>Директна имунофлуоресценция:</strong> </li><ul><li><p><strong>Провеждане:</strong> Използва се кожа на пациента, взета чрез биопсия. В лабораторни условия се подготвят замразени срези от тъканта. Те се третират с античовешки хиперимунен серум, който е предварително „белязан“ (конюгиран) с флуоресциращи вещества (флуорохроми).</p><br></li><li><p><strong>Механизъм:</strong> Ако в кожните структури на болния са се отложили антитела или компоненти на комплемента, античовешкият серум се свързва с тях, образувайки своеобразен „сандвич“. При наблюдение под флуоресцентен микроскоп, тези участъци светят (флуоресцират).</p><br></li></ul><li><p><strong>Индиректна имунофлуоресценция:</strong></p><br></li><ul><li><p><strong>Провеждане:</strong> Използва се епителна тъкан от животински произход, която служи като субстрат. Върху нея се накапва серумът на пациента, в който се подозира наличието на циркулиращи автоантитела.</p></li><li><p><strong>Механизъм:</strong> Ако в серума има специфични антитела, те се свързват с епителните структури на субстрата. След това се добавя белязан с флуорохром античовешки хиперимунен серум, който маркира местата на свързване. Чрез прилагане на различни разреждания на серума може да се определи титърът (концентрацията) на антителата в кръвта на болния.</p></li></ul></ul><h3>6.2. Приложение</h3><p>Методите са незаменими при диагностиката на:</p><ul><li><strong>Автоимунни булозни дерматози:</strong> Пемфигус (<em>pemphigus</em>), болест на Duhring, пемфигоид (<em>pemphigoid</em>).</li><li><strong>Болести на съединителната тъкан:</strong> Лупус (<em>lupus erythematosus</em>), склеродермия (<em>sclerodermia</em>), синдром на Sharp и др.</li></ul><hr><h2>7. Функционални методи за изследване на кожата</h2><p>В дерматологията се използват функционални методи за определяне състоянието на кожата, като за целта се прилагат голям брой апарати за обективизиране на резултатите.</p><table><tbody><tr><td><strong><font color=\"#588157\">Метод / Показател</font></strong></td><td><strong><font color=\"#588157\">Апаратура за изследване</font></strong></td></tr><tr><td><strong>Еластичност</strong></td><td>Еластомери</td></tr><tr><td><strong>Себумна секреция</strong></td><td>Себуметри</td></tr><tr><td><strong>Изпотяване</strong></td><td>Судориметри, евапориметри</td></tr><tr><td><strong>Дебелина и тумори</strong></td><td>Сонография (дерматосонограф)</td></tr><tr><td><strong>Кръвообращение</strong></td><td>Капиляроскопия, осцилометрия, плетизмография</td></tr><tr><td><strong>Температура</strong></td><td>Контактен електротермометър, термография</td></tr><tr><td><strong>Космен цикъл</strong></td><td>Трихограма</td></tr></tbody></table><h3>Клинична значимост на функционалните методи:</h3><div><p>Функционалните изследвания допринасят за изграждането на клиничната диагноза и отчитането на ефекта от приложеното лечение:</p></div><ul><li><strong>Фоточувствителност:</strong> Критична за диагностициране на фотодерматози.</li><li><strong>Капиляроскопия:</strong> Ценен метод при болест на Raynaud, акроцианоза и прогресираща склеродермия. </li><li><strong>Еластичност:</strong> Доказателствен метод при прогресираща склеродермия,<em>pseudoxanthoma elasticum </em>и др.</li></ul><br></div><br></div><ol></ol><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\[', right: '\\]', display: true},\n    {left: '\\(', right: '\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Дерматология и венерология/Теми/3-msg-Лош текст за презентация.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Лош текст за презентация</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\"></h1><h1>МЕТОДИ НА ИЗСЛЕДВАНЕ В ДЕРМАТОЛОГИЯТА</h1><h2>ВЪВЕДЕНИЕ</h2><p>В дерматологията диагностиката има особеност: кожата и лигавиците са директно достъпни за наблюдение и това позволява проследяване на измененията в различните етапи от тяхната еволюция. Практическият подход е поетапен: първо системен клиничен преглед, след това специфични клинични тестове и накрая лабораторно и морфологично потвърждение. Най-голяма диагностична стойност има интеграцията между клиничната картина и параклиничните резултати.</p><h2>1) КЛИНИЧНИ МЕТОДИ: INSPECTIO И PALPATIO</h2><p>Inspectio е основният и най-често използван метод. Огледът трябва да се извършва при достатъчна разсеяна дневна светлина и да обхваща цялата кожа, видимите лигавици, гениталната и перианалната област, както и кожните придатъци - косми и нокти. Ключов принцип е системният преглед, а не фокусиране само върху лезията, за която пациентът съобщава.</p><p>При огледа се оценяват:</p><ul><li>особеностите на незасегнатата кожа (цвят, влажност, омазняване, релеф);</li><li>морфологията на обрива (първични и вторични елементи);</li><li>локализацията и разпределението (ограничено, регионално, сегментно, генерализирано);</li><li>начинът на подреждане (дисеминирано, агминирано, конфлуиращо);</li><li>симетричност и граници на лезиите.</li></ul><p>Palpatio допълва огледа чрез оценка на плътност, инфилтрация, дълбочина, температура, тургор, влажност и болезненост. Палпаторно може да се установи флуктация при гнойни колекции и да се прецени ангажиране на подлежащи тъкани. Необходимо е и палпиране на периферни лимфни възли, особено при съмнение за инфекциозен или системен процес.</p><h2>2) СПЕЦИФИЧНИ КЛИНИЧНИ ТЕСТОВЕ</h2><p>Специфичните тестове имат бърза ориентировъчна стойност и подпомагат диференциалната диагноза още на клинично ниво.</p><p>Дермографизмът отразява съдовата реактивност на кожата. Frictio подпомага установяването на симптома на Darier при мастоцитоза и симптома на Nikolsky при акантолитични булозни дерматози. Системното остъргване (кюртаж) е полезно при псориазис за демонстриране на знака на Auspitz.</p><p>Диаскопията (витропресия) позволява да се разграничат хиперемични от хеморагични изменения, тъй като хеморагичните лезии не избледняват при натиск. Огледът с лупа и дерматоскопията дават възможност за по-детайлна оценка на обривни елементи, включително при пигментни лезии и ранно съмнение за малигнен меланом.</p><p>Допълнително, при някои състояния се използват методи за маркиране на кожата и елементарна оценка на сетивността, които имат практическа стойност в амбулаторната работа.</p><h2>3) ОБЩИ ПАРАКЛИНИЧНИ И МОРФОЛОГИЧНИ ИЗСЛЕДВАНИЯ</h2><p>Рутинните лабораторни изследвания на кръв и урина са задължителни за оценка на общото състояние на пациента и за откриване на насочващи промени. Например еозинофилия може да подкрепи алергична генеза, ускорена СУЕ насочва към активен възпалителен процес, а метаболитни отклонения като хипергликемия често съпътстват рецидивиращи инфекции.</p><p>Сред морфологичните методи цитологичното изследване (проба на Tzanck) е бърз и полезен подход при булозни дерматози и някои вирусно асоциирани лезии. Най-висока доказателствена стойност има хистопатологичното изследване от кожна биопсия, особено при хронични, неопластични или клинично неясни случаи. При нужда се добавят хистохимични и имунохистохимични техники, както и електронномикроскопски анализ при определени генодерматози.</p><h2>4) АЛЕРГОЛОГИЧНИ МЕТОДИ</h2><p>Алергологичната диагностика включва директни (in vivo) и индиректни (in vitro) методи. В практиката широко приложение имат епикутанните проби (patch test), особено при контактни дерматити, както и скарификационни и интрадермални тестове при подходящи показания.</p><p>Към диагностичния процес спадат и елиминационни, експозиционни и провокационни подходи, чрез които се търси причинно-следствена връзка между алергена и клиничната симптоматика. Важно клинично правило е, че отрицателният резултат от един тест не изключва сензибилизация; резултатите винаги се интерпретират в контекста на анамнезата и обективния статус.</p><h2>5) МИКОЛОГИЧНИ И МИКРОБИОЛОГИЧНИ ИЗСЛЕДВАНИЯ</h2><p>При съмнение за микотична етиология се използват няколко основни подхода: изследване със светлина на Wood, нативен препарат с калиева основа, културелно изследване и при нужда хистологична или серологична верификация. Тази комбинация позволява както бързо насочване, така и етиологично потвърждение.</p><p>При инфекциозни дерматози и полово предавани инфекции микробиологичната диагностика включва директна микроскопия, културелно изолиране и антибиограма, което е ключово за избор на правилна антимикробна терапия. Молекулярно-биологичните методи, включително PCR, повишават чувствителността и специфичността на диагностиката, особено при трудно доказуеми причинители.</p><h2>6) ИМУНОФЛУОРЕСЦЕНТНИ И ФУНКЦИОНАЛНИ МЕТОДИ</h2><p>Имунофлуоресцентните методи са фундаментални при автоимунни булозни дерматози и заболявания на съединителната тъкан. Директната имунофлуоресценция доказва отлагания на имуноглобулини и комплемент в кожата, а индиректната - циркулиращи автоантитела в серума.</p><p>Функционалните методи обективизират параметри като еластичност, себумна секреция, изпотяване, микроциркулация, температура и космен цикъл. Те са ценни не само за диагностиката, но и за проследяване на активността на заболяването и терапевтичния отговор.</p>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\[', right: '\\]', display: true},\n    {left: '\\(', right: '\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>"};
